"""Плоские параметры эксперимента из ExperimentResult."""from __future__ import annotationsfrom typing import Anyfrom ..core.types import ExperimentResult_INTERNAL_KEY = "upstream"def signal_params(result: ExperimentResult) -> dict[str, Any]:    return {k: v for k, v in result.clean.params.items() if k != _INTERNAL_KEY}def noise_params(result: ExperimentResult) -> dict[str, Any]:    return {k: v for k, v in result.noisy.params.items() if k != _INTERNAL_KEY}def filter_params(result: ExperimentResult) -> dict[str, Any]:    return {k: v for k, v in result.restored.params.items() if k != _INTERNAL_KEY}def flatten(result: ExperimentResult) -> dict[str, dict[str, Any]]:    return {        "signal": signal_params(result),        "noise": noise_params(result),        "filter": filter_params(result),    }